// Renders the parsed+merged registry into the Vulkan binding core:
// scoped enums, option sets, typed handles, dispatch tables, and inventories.

private let header = """
// Generated by VulkanGen (swiftpm/tools/VulkanGen) — do not edit.
//
// Vulkan binding: scoped enums, option sets, typed handles, a typed
// shadow Swift stdlib or other modules; dispatch tables are typed against
// the raw `PFN_vk*` function-pointer typedefs imported from VulkanC.

public import VulkanC

/// Cast a loader-returned void function pointer to a typed PFN. Returns nil
/// when the command is unavailable (extension not enabled / not present).
@inline(always)
func vkLoad<T>(_ p: PFN_vkVoidFunction?, as type: T.Type) -> T? {
    guard let p else { return nil }
    return unsafeBitCast(p, to: T.self)
}


"""

final class Emitter {
    let idr: IdRenderer
    let vulkanExts: Set<String>
    var declMap: [String: DeclType] = [:]
    var out = ""

    init(idr: IdRenderer, vulkanExts: Set<String>) {
        self.idr = idr
        self.vulkanExts = vulkanExts
    }

    func render(_ registry: Registry) -> String {
        for decl in registry.decls { declMap[decl.name] = decl.type }

        out += header
        out += "public enum VK {\n"

        var seenTypes = Set<String>()
        for decl in registry.decls {
            switch decl.type {
            case .enumeration(let e):
                if e.isBitmask { continue }
                if !seenTypes.insert(decl.name).inserted { continue }
                renderEnum(decl.name, e)
            case .bitmask(let bitsEnum, let bitwidth):
                if !seenTypes.insert(decl.name).inserted { continue }
                renderBitmask(decl.name, bitsEnum: bitsEnum, bitwidth: bitwidth)
            case .handle(let isDispatchable):
                if !seenTypes.insert(decl.name).inserted { continue }
                renderHandle(decl.name, isDispatchable: isDispatchable)
            default:
                break
            }
        }

        renderInventory(registry)
        renderDispatchTables(registry)

        out += "}\n"
        return out
    }

    // --- value vocabulary ---------------------------------------------------

    private func renderEnum(_ vkName: String, _ e: EnumDecl) {
        let typeName = self.typeName(vkName)
        let isResult = vkName == "VkResult"

        out += "    public enum \(typeName): Int32, Equatable, Hashable, Sendable {\n"

        var seenValues = Set<Int32>()
        var seenMembers = Set<String>()
        var aliased: [EnumField] = []

        for field in e.fields {
            if case .alias = field.value { aliased.append(field); continue }
            let value = enumValue(field.value)
            let member = enumMember(vkName, field.name)
            if !seenMembers.insert(member).inserted { continue }
            if !seenValues.insert(value).inserted { aliased.append(field); continue }
            out += "        case \(member) = \(value)\n"
        }

        for field in aliased {
            let member = enumMember(vkName, field.name)
            if !seenMembers.insert(member).inserted { continue }
            let targetName: String
            if case .alias(let a) = field.value { targetName = a } else { targetName = field.name }
            let target = enumMember(vkName, targetName)
            if member == target { continue }
            out += "        public static let \(member) = \(typeName).\(target)\n"
        }

        if isResult {
            out += "        /// Non-negative codes (VK_SUCCESS and the *_KHR success\n"
            out += "        /// variants) report success; negative codes are errors.\n"
            out += "        public var isSuccess: Bool { rawValue >= 0 }\n"
            out += "        public var isError: Bool { rawValue < 0 }\n"
        }

        out += "    }\n"
    }

    private func renderBitmask(_ vkName: String, bitsEnum: String?, bitwidth: Int) {
        let typeName = self.typeName(vkName)
        let intType = bitwidth == 64 ? "UInt64" : "UInt32"

        out += "    public struct \(typeName): OptionSet, Equatable, Hashable, Sendable {\n"
        out += "        public let rawValue: \(intType)\n"
        out += "        public init(rawValue: \(intType)) { self.rawValue = rawValue }\n"

        if let bitsName = bitsEnum, case .enumeration(let bitsDecl)? = declMap[bitsName] {
            var seenMembers = Set<String>()
            for field in bitsDecl.fields {
                if case .alias = field.value { continue }
                let member = flagMember(bitsName, field.name)
                if !seenMembers.insert(member).inserted { continue }
                let raw: UInt64
                switch field.value {
                case .bitpos(let p): raw = UInt64(1) << p
                case .bitVector(let bv): raw = UInt64(bitPattern: Int64(bv)) & 0xFFFF_FFFF
                case .int(let n): raw = UInt64(bitPattern: Int64(n)) & 0xFFFF_FFFF
                case .alias: continue
                }
                if raw == 0 {
                    out += "        public static let \(member) = \(typeName)([])\n"
                } else {
                    out += "        public static let \(member) = \(typeName)(rawValue: 0x\(String(raw, radix: 16, uppercase: true)))\n"
                }
            }
        }

        out += "    }\n"
    }

    private func renderHandle(_ vkName: String, isDispatchable: Bool) {
        let typeName = self.typeName(vkName)
        if isDispatchable {
            out += "    public struct \(typeName): Equatable, Hashable, @unchecked Sendable {\n"
            out += "        public var raw: OpaquePointer?\n"
            out += "        public init(_ raw: OpaquePointer? = nil) { self.raw = raw }\n"
            out += "        public static let null = \(typeName)(nil)\n"
            out += "        public var isNull: Bool { raw == nil }\n"
            out += "    }\n"
        } else {
            out += "    public struct \(typeName): Equatable, Hashable, Sendable {\n"
            out += "        public var raw: UInt64\n"
            out += "        public init(_ raw: UInt64 = 0) { self.raw = raw }\n"
            out += "        public static let null = \(typeName)(0)\n"
            out += "        public var isNull: Bool { raw == 0 }\n"
            out += "    }\n"
        }
    }

    // --- dispatch + inventory -----------------------------------------------

    private enum DispatchLevel { case base, instance, device }

    private func resolveCommandName(_ start: String) -> String? {
        var name = start
        var guardCount = 0
        while guardCount < 32 {
            guard let decl = declMap[name] else { return nil }
            switch decl {
            case .command: return name
            case .aliasCommand(let aliasName): name = aliasName
            default: return nil
            }
            guardCount += 1
        }
        return nil
    }

    private func classify(_ name: String, firstParamTypeName: String?) -> DispatchLevel {
        switch name {
        case "vkGetInstanceProcAddr": return .base
        case "vkGetDeviceProcAddr": return .instance
        case "vkEnumerateInstanceVersion": return .base
        case "vkEnumerateInstanceExtensionProperties": return .base
        case "vkEnumerateInstanceLayerProperties": return .base
        case "vkCreateInstance": return .base
        default: break
        }
        switch firstParamTypeName {
        case "VkDevice", "VkCommandBuffer", "VkQueue": return .device
        case "VkInstance": return .instance
        default: return .instance
        }
    }

    private func buildAvailableCommands(_ registry: Registry) -> Set<String> {
        var set = Set<String>()
        for feature in registry.features {
            for req in feature.requires {
                for c in req.commands {
                    if let canon = resolveCommandName(c) { set.insert(canon) }
                }
            }
        }
        for ext in registry.extensions {
            if ext.platform != nil { continue }
            if ext.extensionType == .video { continue }
            if !vulkanExts.contains(ext.name) { continue }
            for req in ext.requires {
                for c in req.commands {
                    if let canon = resolveCommandName(c) { set.insert(canon) }
                }
            }
        }
        return set
    }

    private func renderDispatchTables(_ registry: Registry) {
        let available = buildAvailableCommands(registry)
        let levels: [(DispatchLevel, String)] = [
            (.base, "BaseDispatch"), (.instance, "InstanceDispatch"), (.device, "DeviceDispatch"),
        ]

        for (lvl, typeName) in levels {
            out += "    public struct \(typeName): @unchecked Sendable {\n"

            var seen = Set<String>()
            if lvl == .base {
                out += "        public let vkGetInstanceProcAddr: PFN_vkGetInstanceProcAddr\n"
                seen.insert("vkGetInstanceProcAddr")
            }
            for decl in registry.decls {
                guard case .command(let firstParam) = decl.type else { continue }
                if !available.contains(decl.name) { continue }
                if classify(decl.name, firstParamTypeName: firstParam) != lvl { continue }
                if !seen.insert(decl.name).inserted { continue }
                out += "        public let \(decl.name): PFN_\(decl.name)?\n"
            }

            switch lvl {
            case .base:
                out += "        public init(loader: PFN_vkGetInstanceProcAddr) {\n            self.vkGetInstanceProcAddr = loader\n"
            case .instance:
                out += "        public init(_ handle: VkInstance?, loader: PFN_vkGetInstanceProcAddr) {\n"
            case .device:
                out += "        public init(_ handle: VkDevice?, loader: PFN_vkGetDeviceProcAddr) {\n"
            }
            seen.removeAll(keepingCapacity: true)
            if lvl == .base { seen.insert("vkGetInstanceProcAddr") }
            let loaderArg = lvl == .base ? "nil" : "handle"
            for decl in registry.decls {
                guard case .command(let firstParam) = decl.type else { continue }
                if !available.contains(decl.name) { continue }
                if classify(decl.name, firstParamTypeName: firstParam) != lvl { continue }
                if !seen.insert(decl.name).inserted { continue }
                out += "            self.\(decl.name) = vkLoad(loader(\(loaderArg), \"\(decl.name)\"), as: PFN_\(decl.name).self)\n"
            }
            out += "        }\n    }\n"
        }
    }

    private func renderInventory(_ registry: Registry) {
        out += "    public struct FeatureLevel: Equatable, Sendable {\n"
        out += "        public let name: String\n"
        out += "        public let major: UInt32\n"
        out += "        public let minor: UInt32\n"
        out += "    }\n"
        out += "    public static let featureLevels: [FeatureLevel] = [\n"
        for feature in registry.features {
            out += "        FeatureLevel(name: \"\(feature.name)\", major: \(feature.level.major), minor: \(feature.level.minor)),\n"
        }
        out += "    ]\n"

        out += "    public enum Ext {\n"
        var seen = Set<String>()
        for ext in registry.extensions {
            if !vulkanExts.contains(ext.name) { continue }
            let nameBytes = bytes(ext.name)
            let tail = startsWith(nameBytes, bytes("VK_")) ? Array(nameBytes[3...]) : nameBytes
            let member = caseName(tail)
            if !seen.insert(member).inserted { continue }
            out += "        public static let \(member) = \"\(ext.name)\"\n"
        }
        out += "    }\n"
    }

    // --- naming -------------------------------------------------------------

    private func typeName(_ vkName: String) -> String {
        sanitize(Array(trimVkNamespace(bytes(vkName))))
    }

    private func enumMember(_ enumName: String, _ fieldName: String) -> String {
        caseName(Array(extractEnumFieldName(bytes(enumName), bytes(fieldName))))
    }

    private func flagMember(_ bitsName: String, _ fieldName: String) -> String {
        caseName(Array(extractBitflagFieldName(bytes(bitsName), bytes(fieldName))))
    }

    private func caseName(_ raw: [UInt8]) -> String {
        if raw.isEmpty { return "value" }
        let tag = idr.getAuthorTag(raw[...])
        let adjusted: ArraySlice<UInt8> = tag != nil ? raw[0..<(raw.count - tag!.count)] : raw[...]
        var buf: [UInt8] = []
        writeCamel(&buf, title: false, adjusted, tag)
        return sanitize(buf)
    }

    private func extractEnumFieldName(_ enumName: [UInt8], _ fieldName: [UInt8]) -> ArraySlice<UInt8> {
        let adjusted = idr.stripAuthorTag(enumName)
        var enumIt = SegmentIterator(adjusted)
        var fieldIt = SegmentIterator(fieldName)
        while true {
            let rest = fieldIt.rest()
            guard let fseg = fieldIt.next() else { return rest }
            guard let eseg = enumIt.next() else { return rest }
            if !eqlIgnoreCase(eseg, fseg) { return rest }
        }
    }

    private func extractBitflagFieldName(_ bitsName: [UInt8], _ fieldName: [UInt8]) -> ArraySlice<UInt8> {
        let flag = bitflagName(bitsName)
        var flagIt = SegmentIterator(flag.base)
        var fieldIt = SegmentIterator(fieldName)
        while true {
            let rest = fieldIt.rest()
            guard let fseg = fieldIt.next() else { return rest }
            guard let flagSeg = flagIt.next() else {
                if let rev = flag.revision, Array(fseg) == rev { return fieldIt.rest() }
                return rest
            }
            if !eqlIgnoreCase(flagSeg, fseg) { return rest }
        }
    }

    private func bitflagName(_ name: [UInt8]) -> (base: [UInt8], revision: [UInt8]?) {
        let tag = idr.getAuthorTag(name[...])
        let tagless: [UInt8] = tag != nil ? Array(name[0..<(name.count - tag!.count)]) : name
        var base = tagless
        while let last = base.last, isDigit(last) { base.removeLast() }
        guard let idx = lastIndexOf(base, bytes("FlagBits")) else { return (base, nil) }
        let revision: [UInt8]? = base.count != tagless.count ? Array(tagless[base.count...]) : nil
        return (Array(base[0..<idx]), revision)
    }
}

private func enumValue(_ value: EnumValue) -> Int32 {
    switch value {
    case .int(let n): return n
    case .bitVector(let bv): return bv
    case .bitpos(let p): return Int32(1) << Int32(p)
    case .alias: return 0
    }
}

private func lastIndexOf(_ haystack: [UInt8], _ needle: [UInt8]) -> Int? {
    if needle.isEmpty || needle.count > haystack.count { return nil }
    var i = haystack.count - needle.count
    while i >= 0 {
        var match = true
        for j in 0..<needle.count where haystack[i + j] != needle[j] { match = false; break }
        if match { return i }
        i -= 1
    }
    return nil
}
